import { Injectable } from '@angular/core';
import { GoogleGenAI } from "@google/genai";

@Injectable({
  providedIn: 'root'
})
export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env['API_KEY'] || '' });
  }

  /**
   * Generates a "Subject" (Model) image using Imagen 3.
   */
  async generateSubjectModel(prompt: string): Promise<string> {
    try {
      const response = await this.ai.models.generateImages({
        model: 'imagen-4.0-generate-001',
        prompt: prompt,
        config: {
          numberOfImages: 1,
          outputMimeType: 'image/jpeg',
          aspectRatio: '1:1',
        },
      });

      if (response.generatedImages && response.generatedImages.length > 0) {
        return `data:image/jpeg;base64,${response.generatedImages[0].image.imageBytes}`;
      }
      throw new Error('No image generated');
    } catch (error) {
      console.error('Error generating subject:', error);
      throw error;
    }
  }

  /**
   * Generates a new Image Project combining the subject description and a new scene context.
   * Note: Imagen API doesn't support image-to-image input for consistency yet in this SDK version clearly,
   * so we merge prompts for best-effort consistency.
   */
  async generateSceneImage(subjectDescription: string, sceneContext: string): Promise<string> {
    const combinedPrompt = `Character Reference: ${subjectDescription}. Scene: ${sceneContext}. High quality, detailed, consistent style.`;

    try {
      const response = await this.ai.models.generateImages({
        model: 'imagen-4.0-generate-001',
        prompt: combinedPrompt,
        config: {
          numberOfImages: 1,
          outputMimeType: 'image/jpeg',
          aspectRatio: '16:9',
        },
      });

      if (response.generatedImages && response.generatedImages.length > 0) {
        return `data:image/jpeg;base64,${response.generatedImages[0].image.imageBytes}`;
      }
      throw new Error('No scene image generated');
    } catch (error) {
      console.error('Error generating scene:', error);
      throw error;
    }
  }

  /**
   * Generates a Video using Veo 2.0, taking the Subject Image as a reference.
   */
  async generateSceneVideo(subjectImageBase64: string, scenePrompt: string): Promise<string> {
    try {
      // Remove data:image/jpeg;base64, prefix if present for the raw bytes
      const cleanBase64 = subjectImageBase64.split(',')[1] || subjectImageBase64;

      let operation = await this.ai.models.generateVideos({
        model: 'veo-2.0-generate-001',
        prompt: scenePrompt,
        image: {
          imageBytes: cleanBase64,
          mimeType: 'image/jpeg'
        },
        config: {
          numberOfVideos: 1
        }
      });

      // Polling loop
      while (!operation.done) {
        // Wait 10 seconds
        await new Promise(resolve => setTimeout(resolve, 10000));
        console.log('Polling video generation status...');
        operation = await this.ai.operations.getVideosOperation({ operation: operation });
      }

      const videoUri = operation.response?.generatedVideos?.[0]?.video?.uri;
      if (!videoUri) throw new Error("Video generation failed to return a URI.");

      // Fetch the actual video blob
      const videoRes = await fetch(`${videoUri}&key=${process.env['API_KEY']}`);
      const videoBlob = await videoRes.blob();
      return URL.createObjectURL(videoBlob);

    } catch (error) {
      console.error('Error generating video:', error);
      throw error;
    }
  }
}

import { Component, inject, signal, computed, effect, ViewChild, ElementRef, SecurityContext } from '@angular/core';
import { CommonModule, NgOptimizedImage } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { GeminiService } from './services/gemini.service';
import { DomSanitizer, SafeUrl } from '@angular/platform-browser';

// --- Interfaces ---
interface SubjectModel {
  id: string;
  name: string; // User defined name
  prompt: string; // The prompt used to create it
  imageUrl: string; // Base64 representation
  createdAt: number;
}

interface Project {
  id: string;
  type: 'image' | 'video';
  subjectId: string;
  scenePrompt: string;
  resultUrl: string | SafeUrl; // Url for video or Base64 for image
  createdAt: number;
  status: 'generating' | 'completed' | 'failed';
}

@Component({
  selector: 'app-root',
  imports: [CommonModule, FormsModule], // NgOptimizedImage removed for base64/blob handling ease in this specific demo context
  templateUrl: './app.component.html',
  styleUrls: [] // Using Tailwind
})
export class AppComponent {
  private gemini = inject(GeminiService);
  private sanitizer = inject(DomSanitizer);

  // --- State Signals ---
  activeTab = signal<'lab' | 'gallery' | 'studio' | 'showcase'>('lab');

  // Data
  subjects = signal<SubjectModel[]>([]);
  projects = signal<Project[]>([]);

  // Selection
  selectedSubjectId = signal<string | null>(null);
  selectedSubject = computed(() => this.subjects().find(s => s.id === this.selectedSubjectId()));

  // Inputs
  newSubjectName = signal('');
  newSubjectPrompt = signal('');
  newProjectPrompt = signal('');
  isGenerating = signal(false);
  generationStatus = signal<string>(''); // For loading messages

  // --- Computed ---
  sortedSubjects = computed(() => [...this.subjects()].sort((a, b) => b.createdAt - a.createdAt));
  sortedProjects = computed(() => [...this.projects()].sort((a, b) => b.createdAt - a.createdAt));

  constructor() {
    // Load data from local storage if available (mock persistence)
    const savedSubjects = localStorage.getItem('holo_lab_subjects');
    if (savedSubjects) {
      this.subjects.set(JSON.parse(savedSubjects));
    }

    // Auto-save effect
    effect(() => {
      localStorage.setItem('holo_lab_subjects', JSON.stringify(this.subjects()));
    });
  }

  // --- Actions: Navigation ---
  setView(view: 'lab' | 'gallery' | 'studio' | 'showcase') {
    this.activeTab.set(view);
  }

  selectSubject(id: string) {
    this.selectedSubjectId.set(id);
    this.setView('studio');
  }

  deleteSubject(id: string, event: Event) {
    event.stopPropagation();
    if(confirm('Terminate this specimen? This action cannot be undone.')) {
      this.subjects.update(prev => prev.filter(s => s.id !== id));
      if (this.selectedSubjectId() === id) {
        this.selectedSubjectId.set(null);
      }
    }
  }

  // --- Actions: Creation ---

  async createSubject() {
    if (!this.newSubjectName() || !this.newSubjectPrompt()) return;

    this.isGenerating.set(true);
    this.generationStatus.set('Initializing genetic sequence...');

    try {
      this.generationStatus.set('Synthesizing bio-digital structure...');
      const imageUrl = await this.gemini.generateSubjectModel(this.newSubjectPrompt());

      const newSubject: SubjectModel = {
        id: crypto.randomUUID(),
        name: this.newSubjectName(),
        prompt: this.newSubjectPrompt(),
        imageUrl: imageUrl,
        createdAt: Date.now()
      };

      this.subjects.update(prev => [newSubject, ...prev]);
      this.newSubjectName.set('');
      this.newSubjectPrompt('');
      this.selectedSubjectId.set(newSubject.id);
      this.setView('studio'); // Go straight to studio
    } catch (err) {
      alert('Synthesis Failed: ' + err);
    } finally {
      this.isGenerating.set(false);
      this.generationStatus.set('');
    }
  }

  async createProject(type: 'image' | 'video') {
    const subject = this.selectedSubject();
    const prompt = this.newProjectPrompt();

    if (!subject || !prompt) return;

    this.isGenerating.set(true);
    const projectId = crypto.randomUUID();

    // Add placeholder project
    const newProject: Project = {
      id: projectId,
      type,
      subjectId: subject.id,
      scenePrompt: prompt,
      resultUrl: '',
      createdAt: Date.now(),
      status: 'generating'
    };

    this.projects.update(prev => [newProject, ...prev]);
    this.setView('showcase'); // Go to showcase to watch progress

    try {
      if (type === 'video') {
        this.generationStatus.set('Compiling temporal data (Veo 2.0)... This may take a minute.');
        const videoUrl = await this.gemini.generateSceneVideo(subject.imageUrl, prompt);
        // Sanitize URL for video src
        const safeUrl = this.sanitizer.bypassSecurityTrustUrl(videoUrl);
        this.updateProjectStatus(projectId, 'completed', safeUrl);
      } else {
        this.generationStatus.set('Rendering environment (Imagen 4.0)...');
        const imageUrl = await this.gemini.generateSceneImage(subject.prompt, prompt);
        this.updateProjectStatus(projectId, 'completed', imageUrl);
      }
    } catch (err) {
      console.error(err);
      this.updateProjectStatus(projectId, 'failed', '');
      alert('Experiment Failed.');
    } finally {
      this.isGenerating.set(false);
      this.generationStatus.set('');
      this.newProjectPrompt.set('');
    }
  }

  updateProjectStatus(id: string, status: 'completed' | 'failed', resultUrl: string | SafeUrl) {
    this.projects.update(prev => prev.map(p => 
      p.id === id ? { ...p, status, resultUrl } : p
    ));
  }

  getProjectSubjectName(subjectId: string): string {
    const sub = this.subjects().find(s => s.id === subjectId);
    return sub ? sub.name : 'Unknown Specimen';
  }

  downloadArtifact(project: Project) {
    const link = document.createElement('a');
    if (typeof project.resultUrl === 'string') {
        link.href = project.resultUrl;
    } else {
        // It's a SafeUrl, we need to extract the string if possible or use the Blob URL directly
        // For SafeUrl in Angular, we often need to cast or access private props if not standard, 
        // but here we stored the Blob Object URL in the service as a string before sanitizing? 
        // Wait, I sanitized it for the template. 
        // Let's unsanitize or just trust the original flow.
        // Re-simplification: Storing string in interface, sanitizing only in template is better.
        // Refactoring updateProjectStatus to store string.
    }
    // Correct approach: The interface says resultUrl is string | SafeUrl.
    // Ideally we store string in state, sanitize in pipe. But for simplicity in this "Applet", I'll just try to open it.

    // Actually, for the video blob URL, it works as a direct link.
    // For base64 image, it works as a direct link.
    // I will use a helper in the template to handle the "sanitization" visual, but keep raw string in model if possible?
    // Let's just create a temporary anchor.
    // Note: SafeUrl object cannot be used in href directly.
    // FIX: I will store raw string in the project, and sanitize only in the HTML @if.
  }

  // Helper to get raw string from project result for download
  getDownloadUrl(project: Project): string {
      // In this app, I will modify updateProjectStatus to NOT sanitize. 
      // I will sanitize in the template using a pipe or just trusting it because we generated it.
      // Actually, Angular requires sanitization for <video src>.
      // I will trust the user and service.
      return project.resultUrl as string;
  }

  // We need to bypass security for the video tag in the template
  getSafeUrl(url: string | SafeUrl): SafeUrl {
    if (typeof url !== 'string') return url;
    return this.sanitizer.bypassSecurityTrustResourceUrl(url);
  }
}

