import { Component, inject, signal, computed, effect, ViewChild, ElementRef, SecurityContext } from '@angular/core';
import { CommonModule, NgOptimizedImage } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { GeminiService } from './services/gemini.service';
import { DomSanitizer, SafeUrl } from '@angular/platform-browser';

// --- Interfaces ---
interface SubjectModel {
  id: string;
  name: string; // User defined name
  prompt: string; // The prompt used to create it
  imageUrl: string; // Base64 representation
  createdAt: number;
}

interface Project {
  id: string;
  type: 'image' | 'video';
  subjectIds: string[]; // Updated to array
  scenePrompt: string;
  resultUrl: string | SafeUrl; 
  createdAt: number;
  status: 'generating' | 'completed' | 'failed';
}

@Component({
  selector: 'app-root',
  imports: [CommonModule, FormsModule],
  templateUrl: './app.component.html',
  styleUrls: [] 
})
export class AppComponent {
  private gemini = inject(GeminiService);
  private sanitizer = inject(DomSanitizer);

  // --- State Signals ---
  activeTab = signal<'lab' | 'gallery' | 'studio' | 'showcase'>('lab');

  // Data
  subjects = signal<SubjectModel[]>([]);
  projects = signal<Project[]>([]);

  // Selection (Multiple)
  selectedSubjectIds = signal<Set<string>>(new Set());

  // Computed Helpers
  selectedSubjects = computed(() => {
    const ids = this.selectedSubjectIds();
    return this.subjects().filter(s => ids.has(s.id));
  });

  // The first selected subject is considered the "Primary" or "Leader" for video reference
  primarySubject = computed(() => this.selectedSubjects()[0] || null);

  // Inputs
  newSubjectName = signal('');
  newSubjectPrompt = signal('');
  newProjectPrompt = signal('');
  isGenerating = signal(false);
  generationStatus = signal<string>('');

  // --- Computed ---
  sortedSubjects = computed(() => [...this.subjects()].sort((a, b) => b.createdAt - a.createdAt));
  sortedProjects = computed(() => [...this.projects()].sort((a, b) => b.createdAt - a.createdAt));

  constructor() {
    // Load data
    const savedSubjects = localStorage.getItem('holo_lab_subjects_v2');
    if (savedSubjects) {
      this.subjects.set(JSON.parse(savedSubjects));
    }
    const savedProjects = localStorage.getItem('holo_lab_projects_v2');
    if (savedProjects) {
        // Migration logic if needed, skipping for now
    }

    // Auto-save effect
    effect(() => {
      localStorage.setItem('holo_lab_subjects_v2', JSON.stringify(this.subjects()));
    });
  }

  // --- Actions: Navigation ---
  setView(view: 'lab' | 'gallery' | 'studio' | 'showcase') {
    this.activeTab.set(view);
  }

  // --- Actions: Selection ---
  toggleSubject(id: string) {
    this.selectedSubjectIds.update(prev => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
      } else {
        next.add(id);
      }
      return next;
    });
  }

  clearSelection() {
    this.selectedSubjectIds.set(new Set());
  }

  deleteSubject(id: string, event: Event) {
    event.stopPropagation();
    if(confirm('Permanently delete this character model?')) {
      this.subjects.update(prev => prev.filter(s => s.id !== id));
      this.selectedSubjectIds.update(prev => {
         const next = new Set(prev);
         next.delete(id);
         return next;
      });
    }
  }

  // --- Actions: Creation ---

  async createSubject() {
    if (!this.newSubjectName() || !this.newSubjectPrompt()) return;

    this.isGenerating.set(true);
    this.generationStatus.set('Initializing Neural Synthesis...');

    try {
      this.generationStatus.set('Rendering Bio-Digital Assets...');
      const imageUrl = await this.gemini.generateSubjectModel(this.newSubjectPrompt());

      const newSubject: SubjectModel = {
        id: crypto.randomUUID(),
        name: this.newSubjectName(),
        prompt: this.newSubjectPrompt(),
        imageUrl: imageUrl,
        createdAt: Date.now()
      };

      this.subjects.update(prev => [newSubject, ...prev]);
      this.newSubjectName.set('');
      this.newSubjectPrompt('');

      // Auto-select and go to gallery to build squad
      this.toggleSubject(newSubject.id);
      this.setView('gallery'); 
    } catch (err) {
      alert('Synthesis Failed: ' + err);
    } finally {
      this.isGenerating.set(false);
      this.generationStatus.set('');
    }
  }

  async createProject(type: 'image' | 'video') {
    const squad = this.selectedSubjects();
    const prompt = this.newProjectPrompt();

    if (squad.length === 0 || !prompt) return;

    this.isGenerating.set(true);
    const projectId = crypto.randomUUID();
    const subjectIds = squad.map(s => s.id);

    // Construct Combined Prompt
    let fullPrompt = "";
    if (squad.length === 1) {
        fullPrompt = `Character: ${squad[0].prompt}. Action/Scene: ${prompt}. High quality 3d render.`;
    } else {
        const charDescriptions = squad.map((s, i) => `[Character ${i+1} (${s.name}): ${s.prompt}]`).join(" ");
        fullPrompt = `A scene featuring multiple characters: ${charDescriptions}. Scene Description: ${prompt}. Ensure all characters are interacting in the same environment. High quality 3d render.`;
    }

    // Add placeholder project
    const newProject: Project = {
      id: projectId,
      type,
      subjectIds: subjectIds,
      scenePrompt: prompt,
      resultUrl: '',
      createdAt: Date.now(),
      status: 'generating'
    };

    this.projects.update(prev => [newProject, ...prev]);
    this.setView('showcase'); 

    try {
      if (type === 'video') {
        this.generationStatus.set('Veo 2.0 Generating Temporal Stream...');
        // Use primary subject for visual anchor, but full prompt for context
        const primary = this.primarySubject(); 
        if (!primary) throw new Error("No primary subject");

        const videoUrl = await this.gemini.generateSceneVideo(primary.imageUrl, fullPrompt);
        const safeUrl = this.sanitizer.bypassSecurityTrustUrl(videoUrl);
        this.updateProjectStatus(projectId, 'completed', safeUrl);
      } else {
        this.generationStatus.set('Imagen 4.0 Rendering Complex Scene...');
        const imageUrl = await this.gemini.generateSceneImage(fullPrompt);
        this.updateProjectStatus(projectId, 'completed', imageUrl);
      }
    } catch (err) {
      console.error(err);
      this.updateProjectStatus(projectId, 'failed', '');
      alert('Mission Failed: ' + err);
    } finally {
      this.isGenerating.set(false);
      this.generationStatus.set('');
      this.newProjectPrompt.set('');
    }
  }

  updateProjectStatus(id: string, status: 'completed' | 'failed', resultUrl: string | SafeUrl) {
    this.projects.update(prev => prev.map(p => 
      p.id === id ? { ...p, status, resultUrl } : p
    ));
  }

  getProjectSubjectNames(subjectIds: string[]): string {
    return subjectIds
      .map(id => this.subjects().find(s => s.id === id)?.name || 'Unknown')
      .join(', ');
  }

  getSafeUrl(url: string | SafeUrl): SafeUrl {
    if (typeof url !== 'string') return url;
    return this.sanitizer.bypassSecurityTrustResourceUrl(url);
  }
}

