        this.generationStatus.set(`Imagen 4.0: Rendering Scena (${ratio})...`);
        const imageUrl = await this.gemini.generateSceneImage(fullPrompt, ratio);
        this.updateProjectStatus(projectId, 'completed', imageUrl);
