// app.component.ts
import { Component, signal, effect, ElementRef, ViewChild } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterOutlet } from '@angular/router';
import { GeminiService } from './gemini.service';
import { FormsModule } from '@angular/forms';
import { NotificationComponent } from './notification.component';

interface Notification {
  message: string;
  type: 'error' | 'info' | 'success';
}

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [CommonModule, RouterOutlet, FormsModule, NotificationComponent],
  templateUrl: './app.component.html',
  styleUrl: './app.component.css'
})
export class AppComponent {
  title = 'google-ai-studio-client';
  prompt = '';
  response = '';
  apiKey = '';
  imageUrl = '';
  isLoading = signal(false);
  imageLoading = signal(false);
  notifications = signal<Notification[]>([]); // Signal for notifications

  constructor(private geminiService: GeminiService) {
    this.apiKey = process.env['API_KEY'] || '';
    if (!this.apiKey) {
      this.addNotification('API Key not found. Please set the API_KEY environment variable.', 'error');
    }
    // Debug to show that the API key is not undefined, but the content is undefined.
    // console.log("API Key from process.env:", this.apiKey);
  }

  addNotification(message: string, type: 'error' | 'info' | 'success') {
    const newNotification: Notification = { message, type };
    this.notifications.update(notifications => [...notifications, newNotification]);

    setTimeout(() => {
      this.notifications.update(notifications => notifications.filter(n => n !== newNotification));
    }, 7000); // Remove after 7 seconds
  }

  async onSubmit() {
    if (!this.apiKey) {
      this.addNotification('API Key is missing. Please set the API_KEY environment variable.', 'error');
      return;
    }

    if (!this.prompt) {
      this.addNotification('Please enter a prompt.', 'info');
      return;
    }

    this.isLoading.set(true);
    this.response = '';
    try {
      this.response = await this.geminiService.getGeminiResponse(this.prompt, this.apiKey);
      this.addNotification('Response retrieved successfully!', 'success');
    } catch (error: any) {
      this.handleGeminiError(error);
    } finally {
      this.isLoading.set(false);
    }
  }

  async onImageSubmit() {
    if (!this.apiKey) {
      this.addNotification('API Key is missing. Please set the API_KEY environment variable.', 'error');
      return;
    }

    if (!this.prompt) {
      this.addNotification('Please enter a prompt for image generation.', 'info');
      return;
    }

    this.imageLoading.set(true);
    this.imageUrl = '';
    try {
      this.imageUrl = await this.geminiService.getImageResponse(this.prompt, this.apiKey);
      this.addNotification('Image generated successfully!', 'success');
    } catch (error: any) {
      this.handleGeminiError(error);
    } finally {
      this.imageLoading.set(false);
    }
  }

  handleGeminiError(error: any) {
    console.error('Gemini API Error:', error);
    let errorMessage = 'An unexpected error occurred.';
    if (error?.response?.data?.error?.message) {
      errorMessage = error.response.data.error.message;
    } else if (error.message) {
      errorMessage = error.message;
    }
    this.addNotification(errorMessage, 'error');
  }
}

